from dataclasses import dataclass
from langchain_openai import ChatOpenAI
from pydantic import BaseModel, Field
import asyncio

@dataclass
class WorkStep:
    var: str          # "#E1", "#E2", ...
    tool: str         # tool name
    input_template: str  # may reference prior vars e.g. "net worth of {#E1}"

class ReWOOPlan(BaseModel):
    steps: list[dict] = Field(
        description="List of {var, tool, input} where input may reference earlier vars like #E1"
    )

PLANNER_PROMPT = """
Given a task and a list of tools, produce a complete dependency-aware plan.
Each step uses the format:
#Ei = ToolName[input]
Where input may reference prior results using {#E1}, {#E2}, etc.

Tools: {tools}
Task: {task}

Plan:
"""

def parse_rewoo_plan(plan_text: str) -> list[WorkStep]:
    """Parse lines like '#E1 = search[CEO of Apple]' into WorkStep objects."""
    import re
    steps = []
    for line in plan_text.splitlines():
        m = re.match(r"(#E\d+)\s*=\s*(\w+)\[(.+?)\]", line.strip())
        if m:
            steps.append(WorkStep(
                var=m.group(1),
                tool=m.group(2),
                input_template=m.group(3).strip(),
            ))
    return steps

def resolve_template(template: str, evidence: dict[str, str]) -> str:
    """Replace {#E1} placeholders with actual evidence values."""
    for var, value in evidence.items():
        template = template.replace("{" + var + "}", value[:300])
    return template

import re

def get_dependencies(step: WorkStep) -> set[str]:
    """Return set of #EN variables referenced in this step's input."""
    return set(re.findall(r"#E\d+", step.input_template))

async def run_worker(steps: list[WorkStep], tools: dict) -> dict[str, str]:
    """Execute all steps, respecting dependencies. Returns {var: result}."""
    evidence: dict[str, str] = {}
    pending = list(steps)

    while pending:
        # Find steps whose dependencies are all resolved
        ready = [
            s for s in pending
            if all(dep in evidence for dep in get_dependencies(s))
        ]
        if not ready:
            raise RuntimeError(f"Circular dependency or unresolvable steps: {[s.var for s in pending]}")

        # Run all ready steps in parallel
        async def exec_step(step: WorkStep) -> tuple[str, str]:
            tool_input = resolve_template(step.input_template, evidence)
            if step.tool not in tools:
                return step.var, f"Error: unknown tool '{step.tool}'"
            try:
                result = await asyncio.to_thread(tools[step.tool], tool_input)
                return step.var, str(result)[:800]
            except Exception as e:
                return step.var, f"Error: {e}"

        results = await asyncio.gather(*(exec_step(s) for s in ready))
        for var, result in results:
            evidence[var] = result
        pending = [s for s in pending if s.var not in evidence]

    return evidence

import tiktoken

def count_tokens(text: str, model: str = "gpt-4o-mini") -> int:
    enc = tiktoken.encoding_for_model(model)
    return len(enc.encode(text))

class TokenBudgetTracker:
    def __init__(self):
        self.total_input = 0
        self.total_output = 0
        self.calls = 0

    def record(self, input_text: str, output_text: str):
        self.total_input  += count_tokens(input_text)
        self.total_output += count_tokens(output_text)
        self.calls += 1

    def report(self) -> dict:
        return {
            "llm_calls": self.calls,
            "total_input_tokens": self.total_input,
            "total_output_tokens": self.total_output,
            "estimated_cost_usd": round(
                self.total_input * 0.00015 / 1000 +   # gpt-4o-mini input price
                self.total_output * 0.0006 / 1000,    # gpt-4o-mini output price
                4
            ),
        }

# Wrap LLM calls
tracker = TokenBudgetTracker()

def tracked_invoke(llm, prompt: str) -> str:
    response = llm.invoke(prompt)
    tracker.record(prompt, response.content)
    return response.content
